import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void clearWinner() {
        assertEquals("visa", new Solution().mostFrequentCardBrand(
            new String[]{"visa", "visa", "mastercard"}));
    }

    @Test
    void tieFirstWins() {
        // mastercard ×2, visa ×2. mastercard first → wins.
        assertEquals("mastercard", new Solution().mostFrequentCardBrand(
            new String[]{"mastercard", "visa", "mastercard", "visa"}));
    }

    @Test
    void single() {
        assertEquals("amex", new Solution().mostFrequentCardBrand(new String[]{"amex"}));
    }

    @Test
    void threeWayWinner() {
        // a×2, b×3 → b
        assertEquals("b", new Solution().mostFrequentCardBrand(
            new String[]{"a", "b", "a", "b", "b"}));
    }
}
